package com.vidaysalud.veterinaria.recetaservicio.controller;import com.vidaysalud.veterinaria.recetaservicio.dto.*;import com.vidaysalud.veterinaria.recetaservicio.service.RecetaService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.time.LocalDateTime;import java.util.*;@RestController @RequestMapping("/api/v1/recetas") @RequiredArgsConstructor public class RecetaController{private final RecetaService s;@GetMapping public ResponseEntity<ApiResponse<List<RecetaResponseDTO>>>l(){return ok("Recetas obtenidas",s.listar());}@GetMapping("/{id}")public ResponseEntity<ApiResponse<RecetaResponseDTO>>b(@PathVariable Integer id){return ok("Receta encontrada",s.buscar(id));}@PostMapping public ResponseEntity<ApiResponse<RecetaResponseDTO>>c(@Valid @RequestBody RecetaRequestDTO d){return ResponseEntity.status(201).body(resp(HttpStatus.CREATED,"Receta creada",s.crear(d)));}@PutMapping("/{id}")public ResponseEntity<ApiResponse<RecetaResponseDTO>>u(@PathVariable Integer id,@Valid @RequestBody RecetaRequestDTO d){return ok("Receta actualizada",s.actualizar(id,d));}@DeleteMapping("/{id}")public ResponseEntity<ApiResponse<Void>>d(@PathVariable Integer id){s.eliminar(id);return ok("Receta eliminada",null);}private<T>ResponseEntity<ApiResponse<T>>ok(String m,T d){return ResponseEntity.ok(resp(HttpStatus.OK,m,d));}private<T>ApiResponse<T>resp(HttpStatus h,String m,T d){return ApiResponse.<T>builder().timestamp(LocalDateTime.now()).status(h.value()).mensaje(m).data(d).build();}}